import React, { useState } from 'react';
import axios from 'axios';
import Expenses from "./components/Expenses/Expenses";
import NewExpense from "./components/NewExpense/NewExpense";

const App = () => {
  const [idNum, setIdNum] = useState(5);
  
  axios.get('./expense-tracker-app/data.json').then(res => console.log(res.data));
  axios.get('./expense-tracker-app/data.json', {id: "3", name: "ilyas"}).then(res => console.log(res.data));

  const expenses = [
    {
      id: "e1",
      title: "Toilet Paper",
      amount: 94.12,
      date: new Date(2020, 7, 14),
    },
    {
      id: "e2",
      title: "New TV",
      amount: 799.49,
      date: new Date(2021, 2, 12),
    },
    {
      id: "e3",
      title: "Car Insurance",
      amount: 294.67,
      date: new Date(2021, 2, 28),
    },
    {
      id: "e4",
      title: "New Desk (Wooden)",
      amount: 450,
      date: new Date(2021, 5, 12),
    },
  ];

  const [expensesData, setExpensesData] = useState(expenses);

  function addExpenseHandler(expense) {
    setIdNum(idNum + 1);
    setExpensesData((prevList) => {
      return [{ ...expense, id: 'e' + idNum }, ...prevList];
    });
  }

  function deleteExpenseHandler(id) {
    setExpensesData((prevList) => {
      return prevList.filter(expense => {
        return expense.id !== id;
      });
    });
  }

  return (
    <div>
      <NewExpense onAddExpenseData={addExpenseHandler} />
      <Expenses items={expensesData} onDelete={deleteExpenseHandler}/>
    </div>
  );
}

export default App;
